configuration.tbelDecoder:
// ---- Safe JSON parsing ----
var json = decodeToJson(payload);
if (json == null) {
  json = {};
}

// ---- Initialize containers ----
var telemetry = {};
var attributes = {}; // Reserved for future use

// ---- Copy all expected fields into telemetry ----
if (json.slave_id != null) {
  telemetry.slave_id = Number(json.slave_id);
}

if (json.switch_closed != null) {
  telemetry.switch_closed = !!json.switch_closed;
}

if (json.fault_status != null) {
  telemetry.fault_status = Number(json.fault_status);
}

if (json.alarm_status != null) {
  telemetry.alarm_status = Number(json.alarm_status);
}

if (json.l1_current_a != null) {
  telemetry.l1_current_a = Number(json.l1_current_a);
}

if (json.l1_voltage_v != null) {
  telemetry.l1_voltage_v = Number(json.l1_voltage_v);
}

if (json.power_factor != null) {
  telemetry.power_factor = Number(json.power_factor);
}

// ---- Return in ThingsBoard format ----
return {
  deviceName: "lab1 station2",
  deviceType: "test",
  attributes: attributes,
  telemetry: telemetry
};
